import SwiftUI

struct CalendarGrid: View {
    let month: Date
    let theme: MonthlyTheme?
    let diaries: [Diary]
    let installDate: Date
    let onDayTap: (Int) -> Void

    private let calendar = Calendar.current
    private let today = Calendar.current.startOfDay(for: Date())
    private let columns = Array(repeating: GridItem(.fixed(50), spacing: 0), count: 7)

    private let weekdays = ["일", "월", "화", "수", "목", "금", "토"]
    private let weekdayColors: [Color] = [
        Color(hex: "C96458"),
        Color(hex: "A2A19F"),
        Color(hex: "A2A19F"),
        Color(hex: "A2A19F"),
        Color(hex: "A2A19F"),
        Color(hex: "A2A19F"),
        Color(hex: "5476BA"),
    ]

    var body: some View {
        VStack(spacing: 0) {
            // Weekday header
            HStack(spacing: 0) {
                ForEach(0..<7, id: \.self) { i in
                    Text(weekdays[i])
                        .font(.gulim(13))
                        .foregroundColor(weekdayColors[i])
                        .frame(width: 50)
                }
            }

            Spacer().frame(height: 13)

            // Calendar grid
            LazyVGrid(columns: columns, spacing: 16) {
                ForEach(0..<month.calendarGridCount, id: \.self) { index in
                    dotCell(at: index)
                }
            }
        }
    }

    private func dotCell(at index: Int) -> some View {
        let (dotState, isTodayCell) = state(for: index)
        return DotCircle(state: dotState, isToday: isTodayCell)
            .onTapGesture {
                let offset = month.firstWeekdayOffset
                guard index >= offset && index < offset + month.daysInMonth else { return }
                if case .future = dotState { return }
                onDayTap(index - offset + 1)
            }
    }

    private func state(for gridIndex: Int) -> (DotState, Bool) {
        let offset = month.firstWeekdayOffset
        let days = month.daysInMonth

        let cell = theme?.pixelArtCells.first(where: { $0.gridIndex == gridIndex })
            ?? PixelArtCell(
                gridIndex: gridIndex,
                backgroundColor: Color(hex: "EDECE9"),
                textColor: .clear,
                text: nil,
                imageName: nil
            )

        // Padding cells (before day 1 or after last day)
        guard gridIndex >= offset && gridIndex < offset + days else {
            return (.padding(cell: cell), false)
        }

        let dayNumber = gridIndex - offset + 1
        let dayDate = calendar.date(byAdding: .day, value: dayNumber - 1, to: month.startOfMonth)!
        let dayStart = calendar.startOfDay(for: dayDate)
        let isTodayCell = dayStart == today
        let installDayStart = calendar.startOfDay(for: installDate)

        // Before install date
        if dayStart < installDayStart {
            return (.preInstall(cell: cell), isTodayCell)
        }

        // Future (strictly after today)
        if dayStart > today {
            return (.future(cell: cell, dayNumber: dayNumber), false)
        }

        // Today or past: check for diary entry
        let hasEntry = diaries.contains { calendar.isDate($0.date, inSameDayAs: dayDate) }

        // Today not yet recorded → treat as future (user can still record)
        if isTodayCell && !hasEntry {
            return (.future(cell: cell, dayNumber: dayNumber), true)
        }

        return hasEntry
            ? (.recorded(cell: cell), isTodayCell)
            : (.missed(cell: cell, dayNumber: dayNumber), isTodayCell)
    }
}

