import ComposableArchitecture
import Foundation

@Reducer
struct MainFeature {
    @ObservableState
    struct State: Equatable {
        var currentMonth: Date = Calendar.current.startOfDay(for: Date()).startOfMonth
        var diaries: [Diary] = []
        var installDate: Date = Date()
    }

    enum Action {
        case onAppear
        case prevMonthTapped
        case nextMonthTapped
        case dayTapped(Date)
        case diariesLoaded([Diary])
        case statisticsTapped
        case exportTapped
    }

    @Dependency(\.diaryClient) var diaryClient

    var body: some ReducerOf<Self> {
        Reduce { state, action in
            switch action {
            case .onAppear:
                if let saved = UserDefaults.standard.object(forKey: "installDate") as? Date {
                    state.installDate = saved
                } else {
                    let now = Date()
                    UserDefaults.standard.set(now, forKey: "installDate")
                    state.installDate = now
                }
                return loadDiaries(for: state.currentMonth)

            case .prevMonthTapped:
                let prev = Calendar.current.date(byAdding: .month, value: -1, to: state.currentMonth)!
                guard prev >= state.installDate.startOfMonth else { return .none }
                state.currentMonth = prev
                return loadDiaries(for: state.currentMonth)

            case .nextMonthTapped:
                let next = Calendar.current.date(byAdding: .month, value: 1, to: state.currentMonth)!
                let maxMonth = Calendar.current.date(byAdding: .month, value: 12, to: Date())!.startOfMonth
                guard next <= maxMonth else { return .none }
                state.currentMonth = next
                return loadDiaries(for: state.currentMonth)

            case .dayTapped:
                // Phase 3: open DiaryWrite sheet
                return .none

            case .diariesLoaded(let diaries):
                state.diaries = diaries
                return .none

            case .statisticsTapped, .exportTapped:
                // Phase 5 / Phase 6
                return .none
            }
        }
    }

    private func loadDiaries(for month: Date) -> Effect<Action> {
        .run { send in
            let diaries = (try? await diaryClient.fetchDiaries(month)) ?? []
            await send(.diariesLoaded(diaries))
        }
    }
}

