/// 설치일부터 어제까지 80% 확률로 일기를 생성 (5번째 날마다 스킵)
private func mockDiaries(from installDate: Date, to lastDay: Date) -> [Diary] {
    var entries: [Diary] = []
    let cal = Calendar.current
    var current = cal.startOfDay(for: installDate)
    let end = cal.startOfDay(for: lastDay)
    var index = 0
    while current <= end {
        if index % 5 != 4 {  // ~80% 기록
            entries.append(Diary(date: current))
        }
        current = cal.date(byAdding: .day, value: 1, to: current)!
        index += 1
    }
    return entries
}

#Preview {
    let testToday = Date.fixed(2027, 3, 30)
    let testInstall = Date.fixed(2026, 4, 15)
    let yesterday = Calendar.current.date(byAdding: .day, value: -1, to: testToday)!
    let allDiaries = mockDiaries(from: testInstall, to: yesterday)

    MainView(
        store: Store(
            initialState: MainFeature.State(
                today: testToday,
                installDate: testInstall
            )
        ) {
            MainFeature()
        } withDependencies: {
            $0.date = .constant(testToday)
            $0.diaryClient.fetchDiaries = { month in
                let cal = Calendar.current
                let y = cal.component(.year, from: month)
                let m = cal.component(.month, from: month)
                return allDiaries.filter {
                    cal.component(.year, from: $0.date) == y &&
                    cal.component(.month, from: $0.date) == m
                }
            }
        }
    )
}

